        ]
      },
      {
        "role": "user",
        "text": "{argument name=\"follow up\" default=\"再生成一份發給團隊的郵件\"}"
      },
      {
        "role": "assistant",
        "type": "code-block",
        "language": "markdown",
        "preview": "郵件正文預覽，開頭致敬，中間結構化要點，結尾簽名"
      }
    ]
  },
  "footer": {
