        "props": [
          "白色乳液質感液滴特寫",
          "圓形 '皮膚科醫生監修' 徽章"
        ]
      },
      "right_column": {
        "subject": "{argument name=\"model description\" default=\"東亞年輕女性，皮膚通透，手指輕觸臉頰\"}",
        "background": "{argument name=\"background\" default=\"虛化的實驗室玻璃器皿背景，明亮乾淨\"}"
      }
    },
    "bottom_features_panel": {
      "left_cards": {
